VALUES
  ('optometrist-moex-00524', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '使用手持式放大鏡時，下列敘述何者錯誤？', '["手持式放大鏡與眼睛的距離越近，像差會減少，視野會增加", "戴雙光眼鏡使用手持式放大鏡，若眼睛到放大鏡的距離大於放大鏡焦距，用雙光上方遠用度區域看放大 鏡，取得較高的放大", "戴雙光眼鏡使用手持式放大鏡，若眼睛到放大鏡的距離小於放大鏡焦距，用雙光下方近用度區域看放大 鏡，取得較高的放大", "手持式放大鏡的倍率越高時，需將放大鏡離物體越遠才看得清楚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00525', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力老年人使用高正度數+12.00D眼鏡，為能夠維持雙眼單一視覺及舒服使用眼鏡，可以使用下列何種 方法來補償？', '["加水平稜鏡度", "加垂直稜鏡度", "加正球面度數", "加圓柱鏡度數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00526', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '一個有-5.00D近視的低視力病人，在不戴眼鏡的狀況下，使用一個物鏡為+10D，目鏡為+20D的望遠鏡：', '["需要鏡筒長度為14公分", "得到的放大倍率為1.5", "需要鏡筒長度為15公分", "得到的放大倍率為2 ×"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00527', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關兒童低視力概況的敘述，下列何者正確？ ×', '["兒童低視力或致盲的病因與國家經濟發展情況無明顯相關", "臺灣兒童低視力常見原因為維生素A缺乏、麻疹眼病變", "兒童低視力的病因無論是先天遺傳或是後天獲得，都對兒童日後的生理及心理發生重大影響", "早期預防治療，對於防治兒童低視力沒有改善效果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00528', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有一低視力患者，其看遠的配鏡處方雙眼皆為平光（plano），而近用眼鏡的處方為雙眼皆為+6.00 DS，為 增加雙眼視力，加上稜鏡後的建議處方為何？', '["右眼及左眼皆為+6.00DS及8Δ基底朝外稜鏡（base-outprism）", "右眼及左眼皆為+6.00DS及2Δ基底朝內稜鏡（base-inprism）", "右眼及左眼皆為+6.00DS及8Δ基底朝內稜鏡（base-inprism）", "右眼及左眼皆為+6.00DS及2Δ基底朝外稜鏡（base-outprism）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00529', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關兒童低視力患者的特色，下列敘述何者錯誤？', '["兒童低視力患者能自然地運用剩餘視力，因而不自覺自身視力低下", "兒童低視力患者因心理因素較為敏感，容易拒絕使用輔具", "兒童低視力患者的復健計畫必須依照年齡不斷變化", "兒童低視力患者進行視力復健時，應主要以父母的期待為主，而非以病童的自身要求為主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00530', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '某75歲個案平時戴+2.50D老花眼鏡搭配一立式放大鏡閱讀；在不更換放大鏡的前提下，若該個案欲擴大 FOV（fieldofview），下列方式何者可行？（設定個案已無有效調節力 –noefficientaccommodation）', '["不改變原本工作距離，直接配戴比原本較高的近用加入度", "不改變原本工作距離，直接配戴比原本較低的近用加入度", "建議個案貼近放大鏡鏡片，同時依相應縮短的工作距離增加近用加入度", "個案無遠方屈光不正，實可拿掉老花眼鏡以裸眼貼近放大鏡鏡片得到最大FOV"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00531', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '想評估低視力嬰幼兒的視力檢查時，那項檢查較不適合？', '["優先注視檢查法", "LeaSymbol測試法", "追隨目標法", "眼電圖（electro-oculogram）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00532', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關低視力視覺損傷的定向行動（orientationandmobility）的敘述，下列何者錯誤？', '["學習定向行動技巧，能夠幫助低視力者，在其生活環境中安全活動", "定向行動技能學習，無需了解和使用殘留視力、距離以及低視力輔具", "對無行動視覺低視力者，可使用白手杖當視覺行動技能，或作為確保安全接觸周遭環境的工具", "定向行動訓練需學習空間和環境概念，以及使用感官接收到的信息來建立、保持或重新獲得方向和行進路線"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00533', 'optometrist', 'optometrist-moex-112-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '造成兒童弱視的病理原因主要為那種組織發育不良？', '["視覺皮質層（visualcortex）", "視網膜神經節細胞（retinalganglioncells）", "視網膜神經纖維層（nervefiberlayer）", "外側膝狀體（lateralgeniculatebody）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "9dcd88633073", "answer_pdf_sha1": "482613c66a88", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
